"""Indeed search results HTML fixture used by parser tests.

Spec: REQ-I-006 / REQ-I-009 / REQ-S-003.

`SEARCH_PAGE_HTML` is a REAL capture of
`https://es.indeed.com/jobs?q=python&l=madrid` taken on 2026-06-02
with `playwright-stealth` (the v1 placeholder was removed in the
`indeed-real-fixture` change). The capture has 16 cards. Indeed's
live DOM uses:
    - `<div class="job_seen_beacon">` (the per-card container; the
      `data-jk` is on the title anchor, not the card).
    - `<a class="jcs-JobTitle" data-jk="...">` (the title link and
      the canonical job id, both on the same anchor).
    - `<span data-testid="company-name">` (the company).
    - `<div data-testid="text-location">` (the location).
    - No inline relative-time string on the card (Indeed renders the
      date asynchronously; the parser returns `None` and the scraper
      falls back to `datetime.now(UTC)` per the
      `parse_indeed_posted_at` docstring).

`BLOCKED_PAGE_HTML` is a synthetic Cloudflare "Security Check"
fixture retained for the `is_indeed_blocked` tests. The live
Cloudflare "Just a moment..." challenge is also matched by the
detector (see `tests/integration/test_indeed_composition.py` /
T-010 partial finding from the closed `indeed_platform` change).

The real capture was performed with the one-off script at
`/tmp/capture_indeed.py` (NOT committed; the script lives in `/tmp`
only for the duration of the T-002 work unit). The capture uses
`playwright-stealth` to bypass Cloudflare's bot detection from the
sandbox IP; from a residential IP the scraper should also work
without stealth on the public SERP, but stealth is the production
default.
"""

from __future__ import annotations

# 15 cards: 3 each of 5 required date strings.
#
# Layout: (data-jk, title, company, location, date_text). The ids
# are 9-digit decimals mirroring the `data-jk` shape on the real
# Indeed SERP. Titles/companies/locations are deterministic so the
# parser tests can pin exact field values.
_CARDS: list[tuple[str, str, str, str, str]] = [
    # Hoy (3 cards)
    (
        "100000001",
        "Senior Python Developer",
        "Indeed Co 1",
        "Madrid, Spain",
        "Hoy",
    ),
    (
        "100000002",
        "Python Backend Engineer",
        "Indeed Co 2",
        "Barcelona, Spain",
        "Hoy",
    ),
    (
        "100000003",
        "Data Engineer Python",
        "Indeed Co 3",
        "Valencia, Spain",
        "Hoy",
    ),
    # Hace 2 horas (3 cards)
    (
        "100000004",
        "Junior Python Developer",
        "Indeed Co 4",
        "Sevilla, Spain",
        "Hace 2 horas",
    ),
    (
        "100000005",
        "Python Full-Stack",
        "Indeed Co 5",
        "Bilbao, Spain",
        "Hace 2 horas",
    ),
    (
        "100000006",
        "DevOps Python",
        "Indeed Co 6",
        "Zaragoza, Spain",
        "Hace 2 horas",
    ),
    # hace 30+ días (3 cards)
    (
        "100000007",
        "Python Architect",
        "Indeed Co 7",
        "Málaga, Spain",
        "hace 30+ días",
    ),
    (
        "100000008",
        "QA Automation Python",
        "Indeed Co 8",
        "Granada, Spain",
        "hace 30+ días",
    ),
    (
        "100000009",
        "Python SRE",
        "Indeed Co 9",
        "Alicante, Spain",
        "hace 30+ días",
    ),
    # Hace 3 días (3 cards)
    (
        "100000010",
        "Machine Learning Engineer",
        "Indeed Co 10",
        "Murcia, Spain",
        "Hace 3 días",
    ),
    (
        "100000011",
        "Python Microservices",
        "Indeed Co 11",
        "Valladolid, Spain",
        "Hace 3 días",
    ),
    (
        "100000012",
        "Backend Python Developer",
        "Indeed Co 12",
        "Salamanca, Spain",
        "Hace 3 días",
    ),
    # Recién publicado (3 cards)
    (
        "100000013",
        "Python Tech Lead",
        "Indeed Co 13",
        "Córdoba, Spain",
        "Recién publicado",
    ),
    (
        "100000014",
        "Python Data Scientist",
        "Indeed Co 14",
        "A Coruña, Spain",
        "Recién publicado",
    ),
    (
        "100000015",
        "Python Backend (Remote)",
        "Indeed Co 15",
        "Remote, Spain",
        "Recién publicado",
    ),
]


def _render_cards() -> str:
    """Render the synthetic card list as a search-results page body."""
    parts: list[str] = []
    for jk, title, company, location, date_text in _CARDS:
        parts.append(
            f"""
      <div class="job_seen_beacon" data-jk="{jk}">
        <h2 class="jobTitle">
          <a href="/viewjob?jk={jk}" title="{title}">{title}</a>
        </h2>
        <span class="companyName">{company}</span>
        <div class="companyLocation">{location}</div>
        <span class="date">{date_text}</span>
      </div>"""
        )
    return "\n".join(parts)


